import React, { useState } from "react";
import Map from "../components/Map";

function Journey() {

  const [currentLocation, setCurrentLocation] = useState(null);
  const [destination, setDestination] = useState(null);
  const [currentName, setCurrentName] = useState("");
  const [destinationName, setDestinationName] = useState("");

  const getLocation = () => {

    navigator.geolocation.getCurrentPosition(async (pos) => {

      const lat = pos.coords.latitude;
      const lon = pos.coords.longitude;

      setCurrentLocation([lat, lon]);

      const res = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}`
      );

      const data = await res.json();

      setCurrentName(data.display_name);

    });

  };

  const updateDestinationName = async (coords) => {

    if (!coords) return;

    const res = await fetch(
      `https://nominatim.openstreetmap.org/reverse?format=json&lat=${coords[0]}&lon=${coords[1]}`
    );

    const data = await res.json();

    setDestinationName(data.display_name);

  };

  React.useEffect(() => {

    updateDestinationName(destination);

  }, [destination]);

  return (

    <div className="container">

      <div className="card">

        <h2>Journey Details</h2>

        <p><b>Current Location:</b></p>
        <p>{currentName || "Not detected"}</p>

        <p><b>Final Location:</b></p>
        <p>{destinationName || "Click on map to choose"}</p>

        <button onClick={getLocation}>
          Detect Current Location
        </button>

        <button className="start">
          Start Journey
        </button>

        <button className="sos">
          SOS Emergency
        </button>

      </div>

      <Map
        currentLocation={currentLocation}
        destination={destination}
        setDestination={setDestination}
      />

    </div>

  )

}

export default Journey;
